  'web.loadingNative': { en: 'Loading native sessions...', it: 'Caricamento sessioni native...', es: 'Cargando sesiones nativas...', fr: 'Chargement des sessions natives...', de: 'Native Sitzungen laden...', pt: 'Carregando sessoes nativas...', ja: '\u30cd\u30a4\u30c6\u30a3\u30d6\u30bb\u30c3\u30b7\u30e7\u30f3\u8aad\u307f\u8fbc\u307f\u4e2d...', zh: '\u52a0\u8f7d\u539f\u751f\u4f1a\u8bdd...', ko: '\ub124\uc774\ud2f0\ube0c \uc138\uc158 \ub85c\ub529 \uc911...', ru: '\u0417\u0430\u0433\u0440\u0443\u0437\u043a\u0430 \u0441\u0435\u0441\u0441\u0438\u0439...' },
  'web.history': { en: 'History (Native Sessions)', it: 'Cronologia (Sessioni Native)', es: 'Historial (Sesiones Nativas)', fr: 'Historique (Sessions Natives)', de: 'Verlauf (Native Sitzungen)', pt: 'Historico (Sessoes Nativas)', ja: '\u5c65\u6b74 (\u30cd\u30a4\u30c6\u30a3\u30d6)', zh: '\u5386\u53f2 (\u539f\u751f\u4f1a\u8bdd)', ko: '\uae30\u3005 (\ub124\uc774\ud2f0\ube0c)', ru: '\u0418\u0441\u0442\u043e\u0440\u0438\u044f (\u043d\u0430\u0442\u0438\u0432\u043d\u044b\u0435 \u0441\u0435\u0441\u0441\u0438\u0438)' },
  'web.noSummary': { en: 'No summary', it: 'Nessun riepilogo', es: 'Sin resumen', fr: 'Pas de resume', de: 'Keine Zusammenfassung', pt: 'Sem resumo', ja: '\u8981\u7d04\u306a\u3057', zh: '\u65e0\u6458\u8981', ko: '\uc694\u7d04 \uc5c6\uc74c', ru: '\u041d\u0435\u0442 \u0441\u0432\u043e\u0434\u043a\u0438' },
